'use strict';
var fs   = require('fs');
var path = require('path');
var userDir = (typeof RED !== 'undefined' && RED.settings && RED.settings.userDir)
    ? RED.settings.userDir : process.cwd();

function findMapPath(dir) {
    var tried = [];
    try {
        var projDir = path.join(dir, 'projects');
        var projects = fs.readdirSync(projDir);
        for (var i = 0; i < projects.length; i++) {
            var p = path.join(projDir, projects[i], 'node-red', 'config', 'ma-cue-map.json');
            tried.push(p);
            if (fs.existsSync(p)) return { path: p, tried: tried };
        }
    } catch(e) {
        if (e.code !== 'ENOENT' && e.code !== 'ENOTDIR') {
            node.warn('[MA Cue Mapper] projects dir scan: ' + e.message);
        }
    }
    var p2 = path.join(dir, 'node-red', 'config', 'ma-cue-map.json');
    tried.push(p2);
    if (fs.existsSync(p2)) return { path: p2, tried: tried };
    var p3 = path.join(dir, 'config', 'ma-cue-map.json');
    tried.push(p3);
    if (fs.existsSync(p3)) return { path: p3, tried: tried };
    return { path: null, tried: tried };
}

var found = findMapPath(userDir);
var mapPath;
var cueMap;

if (!found.path) {
    node.warn('[MA Cue Mapper] ma-cue-map.json not found — using empty map. Tried: ' + found.tried.join(', '));
    mapPath = found.tried[found.tried.length - 1];
    cueMap  = { a1: [], a2: [], a3: [], ls: [] };
} else {
    mapPath = found.path;
    try {
        cueMap = JSON.parse(fs.readFileSync(mapPath, 'utf8'));
        cueMap.a1 = cueMap.a1 || [];
        cueMap.a2 = cueMap.a2 || [];
        cueMap.a3 = cueMap.a3 || [];
        cueMap.ls = cueMap.ls || [];
    } catch (err) {
        node.error('[MA Cue Mapper] Failed to parse map: ' + err.message);
        cueMap = { a1: [], a2: [], a3: [], ls: [] };
    }
}

flow.set('ma_cue_map', cueMap);
flow.set('ma_cue_map_path', mapPath);

if (!flow.get('ma_cmap_form_space'))  flow.set('ma_cmap_form_space',  'a1');
if (!flow.get('ma_cmap_form_label'))  flow.set('ma_cmap_form_label',  '');
if (!flow.get('ma_cmap_form_type'))   flow.set('ma_cmap_form_type',   'sequence');
if (!flow.get('ma_cmap_form_seq'))    flow.set('ma_cmap_form_seq',    1);
if (!flow.get('ma_cmap_form_cue'))    flow.set('ma_cmap_form_cue',    1);
if (!flow.get('ma_cmap_fire_space'))  flow.set('ma_cmap_fire_space',  'a1');
if (!flow.get('ma_cmap_fire_label'))  flow.set('ma_cmap_fire_label',  '');

node.log('[MA Cue Mapper] Loaded from ' + mapPath);
msg.payload = cueMap;
msg.topic   = 'ma/cue-map/loaded';
return msg;

'use strict';
var ALLOWED = ['ma_cmap_form_space','ma_cmap_form_label','ma_cmap_form_type','ma_cmap_form_seq','ma_cmap_form_cue'];
if (msg.topic && ALLOWED.includes(msg.topic)) {
    flow.set(msg.topic, msg.payload);
} else if (msg.topic) {
    node.warn('[MA Cue Mapper] Rejected unknown form key: ' + msg.topic);
}
return null;

'use strict';
var cueMap = flow.get('ma_cue_map') || { a1: [], a2: [], a3: [], ls: [] };
var space  = flow.get('ma_cmap_form_space') || 'a1';
var label  = (flow.get('ma_cmap_form_label') || '').trim();
var type   = flow.get('ma_cmap_form_type')  || 'sequence';
if (type !== 'sequence' && type !== 'executor') {
    node.warn('[MA Cue Mapper] Save: invalid type: ' + type + ' — defaulting to sequence');
    type = 'sequence';
}
var seq    = Number(flow.get('ma_cmap_form_seq') || 1);
var cue    = Number(flow.get('ma_cmap_form_cue') || 1);

if (!label) {
    node.warn('[MA Cue Mapper] Save: cue label is required');
    return null;
}
if (!['a1','a2','a3','ls'].includes(space)) {
    node.warn('[MA Cue Mapper] Save: invalid space: ' + space);
    return null;
}

if (!cueMap[space]) cueMap[space] = [];

var entry = (type === 'sequence')
    ? { label: label, type: 'sequence', sequence: seq, cue: cue }
    : { label: label, type: 'executor', cue: cue };

var idx = cueMap[space].findIndex(function(e) { return e.label === label; });
if (idx >= 0) {
    cueMap[space][idx] = entry;
    node.log('[MA Cue Mapper] Updated: ' + space + '/' + label);
} else {
    cueMap[space].push(entry);
    node.log('[MA Cue Mapper] Added: ' + space + '/' + label);
}

cueMap[space].sort(function(a, b) { return a.label.localeCompare(b.label); });

flow.set('ma_cue_map', cueMap);
msg.filename = flow.get('ma_cue_map_path');
msg.payload  = JSON.stringify(cueMap, null, 2);
msg.cueMap   = cueMap;
return msg;

'use strict';
var cueMap = flow.get('ma_cue_map') || { a1: [], a2: [], a3: [], ls: [] };
var space  = flow.get('ma_cmap_form_space') || 'a1';
var label  = (flow.get('ma_cmap_form_label') || '').trim();

if (!label) {
    node.warn('[MA Cue Mapper] Delete: cue label is required');
    return null;
}
if (!cueMap[space]) {
    node.warn('[MA Cue Mapper] Delete: space not found: ' + space);
    return null;
}

var before = cueMap[space].length;
cueMap[space] = cueMap[space].filter(function(e) { return e.label !== label; });
var removed = before - cueMap[space].length;

if (removed === 0) {
    node.warn('[MA Cue Mapper] Delete: entry not found: ' + space + '/' + label);
    return null;
}

flow.set('ma_cue_map', cueMap);
node.log('[MA Cue Mapper] Deleted: ' + space + '/' + label);

msg.filename = flow.get('ma_cue_map_path');
msg.payload  = JSON.stringify(cueMap, null, 2);
msg.cueMap   = cueMap;
return msg;

'use strict';
msg.payload = flow.get('ma_cue_map') || {};
msg.topic   = 'ma/cue-map/updated';
return msg;

'use strict';
var ALLOWED = ['ma_cmap_fire_space','ma_cmap_fire_label'];
if (msg.topic && ALLOWED.includes(msg.topic)) {
    flow.set(msg.topic, msg.payload);
} else if (msg.topic) {
    node.warn('[MA Cue Mapper] Rejected unknown fire key: ' + msg.topic);
}
return null;

'use strict';
var cueMap = flow.get('ma_cue_map') || { a1: [], a2: [], a3: [], ls: [] };
var space  = flow.get('ma_cmap_fire_space') || 'a1';
var label  = (flow.get('ma_cmap_fire_label') || '').trim();

if (!label) {
    node.warn('[MA Cue Mapper] Fire: cue label is required');
    return [null, { topic: 'ma/cue-map/fire/error', payload: { error: 'No cue label specified' } }];
}

var entries = cueMap[space] || [];
var entry = null;
for (var i = 0; i < entries.length; i++) {
    if (entries[i].label === label) { entry = entries[i]; break; }
}

if (!entry) {
    node.warn('[MA Cue Mapper] Fire: label not found: ' + space + '/' + label);
    return [null, { topic: 'ma/cue-map/fire/error', payload: { error: 'Not found: "' + label + '" in ' + space } }];
}

var maPayload;
if (entry.type === 'sequence') {
    maPayload = { action: 'goSequenceCue', sequence: entry.sequence, cue: entry.cue };
} else {
    maPayload = { action: 'goExecutorCue', zones: [space], cue: entry.cue };
}

node.log('[MA Cue Mapper] Firing: ' + space + '/' + label + ' \u2192 ' + JSON.stringify(maPayload));
return [
    { topic: 'ma/cue-map/fire/' + space, payload: maPayload },
    { topic: 'ma/cue-map/fire/ok', payload: { space: space, label: label, command: maPayload } }
];
